#include <stdio.h>
#include <signal.h>
#include <string.h>

volatile sig_atomic_t count = 0;

void handler(int sig) {
    (void)sig;
    count++;
}

int main(void) {
    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = 0;

    if (sigaction(SIGUSR1, &sa, NULL) == -1) {
        perror("sigaction");
        return 1;
    }
    printf("sigaction installed\n");

    /* Envoyer 3 fois */
    for (int i = 0; i < 3; i++)
        raise(SIGUSR1);

    printf("Signals received: %d\n", count);

    /* Restaurer le comportement par defaut */
    sa.sa_handler = SIG_DFL;
    sigaction(SIGUSR1, &sa, NULL);
    printf("Default restored\n");

    return 0;
}

